def get_browser(pw, headless=True):
    cdp_endpoint = os.environ.get('BROWSER_CDP_ENDPOINT', '')
    if cdp_endpoint:
        try:
            logger.info(f'Connecting to remote browser via CDP: {cdp_endpoint}')
            return pw.chromium.connect_over_cdp(cdp_endpoint)
        except Exception as e:
            logger.warning(f'CDP connection failed ({e}), falling back to local Chromium')
    return pw.chromium.launch(headless=headless, args=['--no-sandbox', '--disable-dev-shm-usage', '--disable-blink-features=AutomationControlled', '--disable-infobars', '--no-first-run'])
